func FindUserAnswer(ctx context.Context, exec boil.ContextExecutor, userID string, questionID int64, selectCols ...string) (*UserAnswer, error) {
	userAnswerObj := &UserAnswer{}

	sel := "*"
	if len(selectCols) > 0 {
		sel = strings.Join(strmangle.IdentQuoteSlice(dialect.LQ, dialect.RQ, selectCols), ",")
	}
	query := fmt.Sprintf(
		"select %s from \"user_answers\" where \"user_id\"=$1 AND \"question_id\"=$2", sel,
	)

	q := queries.Raw(query, userID, questionID)

	err := q.Bind(ctx, exec, userAnswerObj)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, sql.ErrNoRows
		}
		return nil, errors.Wrap(err, "entity: unable to select from user_answers")
	}

	if err = userAnswerObj.doAfterSelectHooks(ctx, exec); err != nil {
		return userAnswerObj, err
	}

	return userAnswerObj, nil
}

